import React, { useEffect, useState } from 'react';
import { Card, Row, Col, Badge, Modal, Button } from 'react-bootstrap';
import { Store, Users, ArrowLeft, CheckCircle, AlertTriangle } from 'lucide-react';
import { searchDocuments } from '../api';
import './ComplianceDashboard.css';

const ComplianceDashboard = () => {
  const [view, setView] = useState('STORE'); // STORE | EMPLOYEE
  const [stores, setStores] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [selectedStore, setSelectedStore] = useState(null);
  const [selectedEmployee, setSelectedEmployee] = useState(null);

  const mandatoryDocs = [
    'ID Proof',
    'Address Proof',
    'Educational Certificate',
    'Employment Contract'
  ];

  useEffect(() => {
    loadData();
  }, []);

  const getStatus = (expiry) => {
    if (!expiry) return 'valid';
    const diff = Math.floor((new Date(expiry) - new Date()) / 86400000);
    if (diff <= 0) return 'expired';
    if (diff <= 30) return 'expiring';
    return 'valid';
  };

  const loadData = async () => {
    const res = await searchDocuments({});
    const docs = res.data.data || [];

    const storeMap = {};
    const empMap = {};

    docs.forEach(doc => {
      const status = getStatus(doc.expiryDate);

      if (!empMap[doc.employeeId]) {
        empMap[doc.employeeId] = {
          id: doc.employeeId,
          name: doc.employeeName,
          store: doc.store,
          documents: [],
          expired: 0
        };
      }

      empMap[doc.employeeId].documents.push({ ...doc, status });
      if (status === 'expired') empMap[doc.employeeId].expired++;

      if (!storeMap[doc.store]) {
        storeMap[doc.store] = {
          store: doc.store,
          employees: [],
          valid: 0,
          expired: 0
        };
      }

      storeMap[doc.store][status]++;
    });

    Object.values(empMap).forEach(emp => {
      emp.missing = mandatoryDocs.filter(
        d => !emp.documents.some(doc => doc.documentType === d)
      );
      emp.compliant = emp.missing.length === 0 && emp.expired === 0;
      storeMap[emp.store].employees.push(emp);
    });

    Object.values(storeMap).forEach(store => {
      const total = store.valid + store.expired;
      store.compliance = total ? Math.round((store.valid / total) * 100) : 0;
    });

    setStores(Object.values(storeMap));
  };

  /* ===========================
     STORE OVERVIEW (LEVEL 1)
  ============================*/
  if (view === 'STORE') {
    return (
      <div className="compliance-dashboard">
        <h3 className="mb-4">
          <Store size={24} className="me-2" />
          Store Compliance Overview
        </h3>

        <Row className="g-4">
          {stores.map(store => (
            <Col md={4} lg={3} key={store.store}>
              <Card
                className="store-card h-100"
                onClick={() => {
                  setSelectedStore(store);
                  setEmployees(store.employees);
                  setView('EMPLOYEE');
                }}
              >
                <Card.Body className="text-center">
                  <h5>{store.store}</h5>

                  <div className="compliance-circle my-3">
                    {store.compliance}%
                  </div>

                  <Badge bg={store.compliance >= 80 ? 'success' : 'danger'}>
                    View Employees →
                  </Badge>
                </Card.Body>
              </Card>
            </Col>
          ))}
        </Row>
      </div>
    );
  }

  /* ===========================
     EMPLOYEE VIEW (LEVEL 2)
  ============================*/
  return (
    <div className="compliance-dashboard">
      <Button
        variant="link"
        className="mb-3"
        onClick={() => setView('STORE')}
      >
        <ArrowLeft size={16} /> Back to Stores
      </Button>

      <h4 className="mb-4">
        <Users size={20} className="me-2" />
        {selectedStore.store} – Employees
      </h4>

      <Row className="g-4">
        {employees
          .sort((a, b) => a.compliant - b.compliant)
          .map(emp => (
            <Col md={4} lg={3} key={emp.id}>
              <Card
                className={`employee-card h-100 ${
                  emp.compliant ? 'border-success' : 'border-danger'
                }`}
                onClick={() => setSelectedEmployee(emp)}
              >
                <Card.Body>
                  <h6>{emp.name}</h6>

                  {emp.compliant ? (
                    <Badge bg="success">
                      <CheckCircle size={14} /> Compliant
                    </Badge>
                  ) : (
                    <Badge bg="danger">
                      <AlertTriangle size={14} /> Pending
                    </Badge>
                  )}

                  <div className="mt-2 small text-muted">
                    Missing: {emp.missing.length}
                  </div>
                </Card.Body>
              </Card>
            </Col>
          ))}
      </Row>

      {/* ===========================
          EMPLOYEE DETAIL MODAL
      ============================*/}
      <Modal
        show={!!selectedEmployee}
        onHide={() => setSelectedEmployee(null)}
        centered
      >
        {selectedEmployee && (
          <>
            <Modal.Header closeButton>
              <Modal.Title>{selectedEmployee.name}</Modal.Title>
            </Modal.Header>

            <Modal.Body>
              <h6>Missing Mandatory Documents</h6>
              {selectedEmployee.missing.length === 0 ? (
                <Badge bg="success">None</Badge>
              ) : (
                <ul>
                  {selectedEmployee.missing.map(doc => (
                    <li key={doc}>{doc}</li>
                  ))}
                </ul>
              )}
            </Modal.Body>

            <Modal.Footer>
              <Button onClick={() => setSelectedEmployee(null)}>
                Close
              </Button>
            </Modal.Footer>
          </>
        )}
      </Modal>
    </div>
  );
};

export default ComplianceDashboard;
